INSERT INTO `v1_caf76554fb9dbf1150400205cfb40d65ccc8dd87cdf2585cd194905467d18fa3` VALUES ("剛力なる鳥像", "ガーゴイル", 101, 0, 1, 0, 1, "高い物理攻撃力を宿し、強力な範囲攻撃を行うよう\nプログラムされたボスが現れる。");
INSERT INTO `v1_caf76554fb9dbf1150400205cfb40d65ccc8dd87cdf2585cd194905467d18fa3` VALUES ("魔業なる鳥像", "マグスガーゴイル", 102, 0, 2, 0, 2, "高い魔法攻撃力を宿し、強力な範囲攻撃を行うよう\nプログラムされたボスが現れる。");
INSERT INTO `v1_caf76554fb9dbf1150400205cfb40d65ccc8dd87cdf2585cd194905467d18fa3` VALUES ("堅固なる鳥像", "ガードガーゴイル", 103, 0, 3, 0, 3, "防御力アップスキルで高い耐久力を誇り、相手の攻撃\nを凌ぐようプログラムされたボスが現れる。");
